{
  "name": "JTRIFT - Premium Local Jacket Brand",
  "description": "A high-end e-commerce platform for JTRIFT, a local Indonesian jacket brand featuring vintage-inspired designs and modern streetwear aesthetics.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Category = 'All' | 'Bomber' | 'Denim' | 'Windbreaker' | 'Vintage' | 'Varsity';

export interface Product {
  id: string;
  name: string;
  price: number;
  description: string;
  category: Category;
  image: string;
  sizes: string[];
  isNew?: boolean;
  stock: number;
}

export interface CartItem extends Product {
  selectedSize: string;
  quantity: number;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
}

import { GoogleGenAI } from "@google/genai";
import { PRODUCTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
You are the JTRIFT AI Personal Stylist. JTRIFT is a local Indonesian jacket brand that focuses on streetwear, varsity, and vintage aesthetics.
Your goal is to help customers find the perfect jacket from our catalog.
Catalog: ${JSON.stringify(PRODUCTS.map(p => ({ name: p.name, price: p.price, category: p.category, description: p.description })))}

Guidelines:
1. Be friendly, trendy, and use a mix of formal and casual Indonesian/English (slang is okay for streetwear context).
2. Recommend specific products based on the user's preferences (e.g., weather, occasion, style).
3. If asked about prices, use IDR format.
4. Keep answers concise and helpful.
5. If the user is unsure, ask about their favorite color or what they usually wear.
`;

export const getStylistResponse = async (userMessage: string, history: { role: 'user' | 'model', text: string }[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        maxOutputTokens: 500,
      }
    });

    return response.text || "Maaf, saya sedang mengalami kendala teknis. Ada yang bisa saya bantu lagi?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Maaf, sepertinya saya sedang istirahat sejenak. Silakan tanya lagi nanti ya!";
  }
};

import React from 'react';

interface NavbarProps {
  cartCount: number;
  onOpenCart: () => void;
  onNavigate: (section: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, onOpenCart, onNavigate }) => {
  return (
    <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">
          <div className="flex items-center cursor-pointer" onClick={() => onNavigate('hero')}>
            <span className="text-3xl font-bold font-heading tracking-tighter text-stone-900">JTRIFT</span>
            <div className="ml-2 w-2 h-2 bg-orange-600 rounded-full"></div>
          </div>

          <div className="hidden md:flex space-x-8">
            <button onClick={() => onNavigate('collection')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Collection</button>
            <button onClick={() => onNavigate('about')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">About Us</button>
            <button onClick={() => onNavigate('contact')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Contact</button>
          </div>

          <div className="flex items-center space-x-5">
            <button className="text-stone-600 hover:text-stone-900">
              <i className="fa-solid fa-magnifying-glass text-xl"></i>
            </button>
            <button 
              onClick={onOpenCart}
              className="relative p-2 text-stone-600 hover:text-stone-900 transition-colors"
            >
