export default Navbar;

import React from 'react';
import { CartItem } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface CartSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (id: string, size: string) => void;
  onUpdateQuantity: (id: string, size: string, delta: number) => void;
}

const CartSidebar: React.FC<CartSidebarProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity }) => {
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[100] overflow-hidden">
      <div className="absolute inset-0 bg-black/50 transition-opacity" onClick={onClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md bg-white shadow-xl flex flex-col">
          <div className="p-6 border-b border-stone-200 flex justify-between items-center">
            <h2 className="text-xl font-bold font-heading">Your Bag</h2>
            <button onClick={onClose} className="text-stone-500 hover:text-stone-900">
              <i className="fa-solid fa-xmark text-2xl"></i>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-400">
                <i className="fa-solid fa-bag-shopping text-6xl mb-4 opacity-20"></i>
                <p>Your bag is empty.</p>
                <button 
                  onClick={onClose}
                  className="mt-4 text-orange-600 font-semibold hover:underline"
                >
                  Go Shopping
                </button>
              </div>
            ) : (
              <ul className="space-y-6">
                {items.map((item) => (
                  <li key={`${item.id}-${item.selectedSize}`} className="flex space-x-4">
                    <img src={item.image} alt={item.name} className="w-20 h-24 object-cover rounded" />
                    <div className="flex-1">
                      <h3 className="font-semibold text-stone-900">{item.name}</h3>
                      <p className="text-sm text-stone-500">Size: {item.selectedSize}</p>
                      <div className="flex items-center justify-between mt-2">
                        <div className="flex items-center border border-stone-200 rounded">
                          <button 
                            onClick={() => onUpdateQuantity(item.id, item.selectedSize, -1)}
                            className="px-2 py-1 hover:bg-stone-100"
                          >
                            <i className="fa-solid fa-minus text-xs"></i>
                          </button>
                          <span className="px-3 py-1 text-sm font-medium">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.id, item.selectedSize, 1)}
                            className="px-2 py-1 hover:bg-stone-100"
                          >
                            <i className="fa-solid fa-plus text-xs"></i>
                          </button>
                        </div>
                        <span className="font-medium">{FORMAT_CURRENCY(item.price * item.quantity)}</span>
                      </div>
                    </div>
                    <button 
                      onClick={() => onRemove(item.id, item.selectedSize)}
                      className="text-stone-400 hover:text-red-500 transition-colors"
                    >
                      <i className="fa-solid fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            )}
          </div>

          <div className="p-6 border-t border-stone-200 bg-stone-50">
            <div className="flex justify-between items-center mb-6">
              <span className="text-stone-600">Subtotal</span>
              <span className="text-xl font-bold">{FORMAT_CURRENCY(total)}</span>
            </div>
            <button 
              disabled={items.length === 0}
              className="w-full py-4 bg-stone-900 text-white font-bold rounded-lg hover:bg-black transition-colors disabled:bg-stone-300 disabled:cursor-not-allowed"
            >
              Checkout Now
            </button>
            <p className="mt-4 text-center text-xs text-stone-500 uppercase tracking-widest">
              Free shipping nationwide for orders over 500k
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartSidebar;

import React, { useState } from 'react';
import { Product } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface ProductCardProps {
  product: Product;
  onAddToCart: (product: Product, size: string) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div 
      className="group relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className="aspect-[3/4] overflow-hidden rounded-2xl bg-stone-200 relative">
        <img 
          src={product.image} 
          alt={product.name} 
          className="h-full w-full object-cover object-center transition-transform duration-700 group-hover:scale-110"
        />
        {product.isNew && (
          <span className="absolute top-4 left-4 bg-orange-600 text-white px-3 py-1 rounded-full text-xs font-bold uppercase tracking-widest">
            New
          </span>
        )}

        {/* Quick Add Overlay */}
        <div className={`absolute inset-0 bg-black/20 backdrop-blur-sm transition-opacity duration-300 flex flex-col justify-end p-6 ${isHovered ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-white rounded-xl p-4 shadow-2xl transform translate-y-0 transition-transform duration-500">
            <p className="text-xs font-bold uppercase text-stone-400 mb-2">Select Size</p>
            <div className="flex flex-wrap gap-2 mb-4">
              {product.sizes.map((size) => (
                <button
                  key={size}
                  onClick={() => setSelectedSize(size)}
                  className={`w-10 h-10 rounded-md border flex items-center justify-center text-sm font-bold transition-all ${
                    selectedSize === size 
                      ? 'bg-stone-900 text-white border-stone-900' 
                      : 'border-stone-200 text-stone-600 hover:border-stone-900'
                  }`}
                >
                  {size}
                </button>
              ))}
            </div>
            <button
              onClick={() => {
                if (selectedSize) {
                  onAddToCart(product, selectedSize);
                  setSelectedSize('');
                } else {
                  alert('Please select a size first');
                }
              }}
              className="w-full bg-orange-600 text-white py-3 rounded-lg font-bold hover:bg-orange-700 transition-colors flex items-center justify-center space-x-2"
            >
              <i className="fa-solid fa-plus text-xs"></i>
              <span>Add to Bag</span>
            </button>
          </div>
        </div>
      </div>

      <div className="mt-4 flex justify-between items-start px-1">
        <div>
          <h3 className="text-lg font-bold text-stone-900 font-heading">{product.name}</h3>
          <p className="mt-1 text-sm text-stone-500">{product.category}</p>
        </div>
        <p className="text-lg font-semibold text-stone-900">{FORMAT_CURRENCY(product.price)}</p>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState, useRef, useEffect } from 'react';
import { getStylistResponse } from '../services/geminiService';
import { Message } from '../types';

const AIStylist: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Hey there! I am your JTRIFT Personal Stylist. Looking for a fresh jacket today? Tell me what you need!' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    const response = await getStylistResponse(userMessage, messages);
    setMessages(prev => [...prev, { role: 'model', text: response }]);
    setIsLoading(false);
  };

  return (
    <div className="fixed bottom-6 right-6 z-[100] flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[400px] h-[500px] bg-white rounded-2xl shadow-2xl flex flex-col border border-stone-200 overflow-hidden animate-in slide-in-from-bottom-5 duration-300">
          <div className="bg-stone-900 p-4 text-white flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 rounded-full bg-orange-600 flex items-center justify-center">
                <i className="fa-solid fa-sparkles"></i>
              </div>
              <div>
                <h3 className="font-bold text-sm">JTRIFT Personal Stylist</h3>
                <div className="flex items-center space-x-1">
                  <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                  <span className="text-[10px] uppercase tracking-widest opacity-70">AI Active</span>
                </div>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:text-stone-400">
              <i className="fa-solid fa-chevron-down"></i>
            </button>
          </div>

          <div 
            ref={scrollRef}
            className="flex-1 overflow-y-auto p-4 space-y-4 custom-scrollbar bg-stone-50"
          >
            {messages.map((msg, idx) => (
              <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                <div className={`max-w-[85%] p-3 rounded-2xl text-sm ${
                  msg.role === 'user' 
                    ? 'bg-orange-600 text-white rounded-br-none' 
                    : 'bg-white border border-stone-200 text-stone-800 rounded-bl-none shadow-sm'
                }`}>
                  {msg.text}
                </div>
              </div>
            ))}
            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-stone-200 p-3 rounded-2xl shadow-sm rounded-bl-none">
                  <div className="flex space-x-1">
                    <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
                    <div className="w-1.5 h-1.5 bg-stone-300 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
                  </div>
                </div>
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-stone-200">
            <div className="flex space-x-2">
              <input 
                type="text" 
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={(e) => e.key === 'Enter' && handleSend()}
                placeholder="Ask me for a recommendation..."
                className="flex-1 bg-stone-100 border-none rounded-lg px-4 py-2 text-sm focus:ring-2 focus:ring-orange-600 focus:bg-white transition-all outline-none"
              />
              <button 
                onClick={handleSend}
                disabled={isLoading}
                className="bg-stone-900 text-white w-10 h-10 rounded-lg flex items-center justify-center hover:bg-black transition-colors disabled:opacity-50"
              >
                <i className="fa-solid fa-paper-plane"></i>
              </button>
            </div>
          </div>
        </div>
      )}

      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-16 h-16 bg-stone-900 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-105 active:scale-95 transition-all group overflow-hidden relative"
      >
        <div className="absolute inset-0 bg-gradient-to-tr from-orange-600/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity"></div>
        {isOpen ? (
          <i className="fa-solid fa-xmark text-2xl"></i>
        ) : (
          <i className="fa-solid fa-wand-magic-sparkles text-2xl"></i>
        )}
      </button>
    </div>
  );
};

export default AIStylist;

import React, { useState, useEffect, useRef } from 'react';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import CartSidebar from './components/CartSidebar';
import AIStylist from './components/AIStylist';
import { PRODUCTS } from './constants';
import { Product, CartItem, Category } from './types';

const App: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category>('All');

  const heroRef = useRef<HTMLDivElement>(null);
  const collectionRef = useRef<HTMLDivElement>(null);
  const aboutRef = useRef<HTMLDivElement>(null);
  const contactRef = useRef<HTMLDivElement>(null);

  const filteredProducts = activeCategory === 'All' 
    ? PRODUCTS 
    : PRODUCTS.filter(p => p.category === activeCategory);

  const addToCart = (product: Product, size: string) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id && item.selectedSize === size);
      if (existing) {
        return prev.map(item => 
          item.id === product.id && item.selectedSize === size 
            ? { ...item, quantity: item.quantity + 1 } 
            : item
        );
      }
      return [...prev, { ...product, selectedSize: size, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string, size: string) => {
    setCartItems(prev => prev.filter(item => !(item.id === id && item.selectedSize === size)));
  };

  const updateQuantity = (id: string, size: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id && item.selectedSize === size) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const scrollToSection = (section: string) => {
    const refs: Record<string, React.RefObject<HTMLDivElement>> = {
      hero: heroRef,
      collection: collectionRef,
      about: aboutRef,
      contact: contactRef,
    };
    refs[section]?.current?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        cartCount={cartItems.reduce((s, i) => s + i.quantity, 0)} 
        onOpenCart={() => setIsCartOpen(true)}
        onNavigate={scrollToSection}
      />

      <main className="flex-grow">
        {/* Hero Section */}
        <section ref={heroRef} className="relative h-[85vh] flex items-center overflow-hidden bg-stone-900">
          <div className="absolute inset-0 opacity-60">
            <img 
              src="https://images.unsplash.com/photo-1555689502-c4b22d76c56f?auto=format&fit=crop&q=80&w=1920" 
              className="w-full h-full object-cover" 
              alt="Streetwear model" 
            />
          </div>
          <div className="absolute inset-0 bg-gradient-to-r from-stone-950 via-stone-900/40 to-transparent"></div>

          <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-white">
            <h1 className="text-6xl md:text-8xl font-black font-heading tracking-tighter leading-none mb-6">
              REDEFINE<br />
              <span className="text-orange-600 italic">HERITAGE.</span>
            </h1>
            <p className="max-w-xl text-lg md:text-xl text-stone-300 mb-10 font-light leading-relaxed">
              Premium local jackets blending vintage aesthetics with modern street silhouettes. Crafted in Indonesia, designed for the world.
            </p>
            <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-6">
              <button 
                onClick={() => scrollToSection('collection')}
                className="px-8 py-4 bg-orange-600 text-white font-bold rounded-lg hover:bg-orange-700 transition-all hover:scale-105 active:scale-95"
              >
                Shop New Arrivals
              </button>
              <button 
                onClick={() => scrollToSection('about')}
                className="px-8 py-4 border border-white/30 backdrop-blur-sm text-white font-bold rounded-lg hover:bg-white hover:text-stone-900 transition-all"
              >
                Explore Story
              </button>
            </div>
          </div>
        </section>

        {/* Categories / Collection */}
        <section ref={collectionRef} className="py-24 bg-white">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 space-y-4 md:space-y-0">
              <div>
                <h2 className="text-4xl font-bold font-heading text-stone-900 tracking-tight">Current Collection</h2>
                <p className="mt-2 text-stone-500">Limited batches, maximum details.</p>
              </div>

              <div className="flex flex-wrap gap-2">
                {(['All', 'Varsity', 'Bomber', 'Windbreaker', 'Vintage', 'Denim'] as Category[]).map((cat) => (
                  <button
                    key={cat}
                    onClick={() => setActiveCategory(cat)}
                    className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
                      activeCategory === cat 
                        ? 'bg-stone-900 text-white' 
                        : 'bg-stone-100 text-stone-500 hover:bg-stone-200'
                    }`}
                  >
                    {cat}
                  </button>
                ))}
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
              {filteredProducts.map(product => (
                <ProductCard 
                  key={product.id} 
                  product={product} 
                  onAddToCart={addToCart} 
                />
              ))}
            </div>
          </div>
        </section>

        {/* Featured Banner */}
        <section className="py-16 bg-stone-100 overflow-hidden">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center space-y-12 md:space-y-0 md:space-x-12">
            <div className="md:w-1/2 relative group">
              <img 
                src="https://images.unsplash.com/photo-1548126032-079a0fb0099d?auto=format&fit=crop&q=80&w=800" 
                className="rounded-3xl shadow-2xl transition-transform group-hover:scale-[1.02] duration-500" 
                alt="Process" 
              />
              <div className="absolute -bottom-6 -right-6 w-32 h-32 bg-orange-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-12">
                <div className="text-center">
                  <span className="block text-4xl font-bold">100%</span>
                  <span className="text-[10px] font-bold uppercase tracking-widest">Local Made</span>
                </div>
              </div>
            </div>
            <div className="md:w-1/2">
              <h2 className="text-4xl font-bold font-heading text-stone-900 leading-tight mb-6">Quality is our only obsession.</h2>
              <p className="text-stone-600 text-lg mb-8">
                Each JTRIFT piece undergoes a rigorous sourcing process. We only use heavy-weight fabrics, YKK zippers, and proprietary embroidery techniques to ensure your jacket lasts for decades, not seasons.
              </p>
              <ul className="space-y-4">
                {[
                  'Hand-distressed denim details',
                  'Heavy-weight 320gsm materials',
                  'Limited run production (Max 50 per style)',
                  'Reinforced stitching for durability'
                ].map((item, idx) => (
                  <li key={idx} className="flex items-center space-x-3 text-stone-700">
                    <i className="fa-solid fa-check text-orange-600"></i>
                    <span className="font-medium">{item}</span>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </section>

        {/* Instagram / Social Proof */}
        <section className="py-24 bg-white border-t border-stone-200">
          <div className="max-w-7xl mx-auto px-4 text-center mb-12">
            <h2 className="text-3xl font-bold font-heading mb-2">Worn by the Community</h2>
