import { GoogleGenAI } from "@google/genai";
import { PRODUCTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
Anda adalah AI Personal Stylist dari JTRIFT. JTRIFT adalah brand jaket lokal Indonesia yang berfokus pada estetika streetwear, varsity, dan vintage.
Tujuan Anda adalah membantu pelanggan menemukan jaket yang sempurna dari katalog kami.
Katalog: ${JSON.stringify(PRODUCTS.map(p => ({ name: p.name, price: p.price, category: p.category, description: p.description })))}

Panduan:
1. Bersikaplah ramah, trendy, dan gunakan campuran Bahasa Indonesia formal dan santai (bahasa gaul streetwear diperbolehkan seperti 'bro', 'sis', 'keren parah', dll).
2. Rekomendasikan produk spesifik berdasarkan preferensi pengguna (misal: cuaca, acara, gaya).
3. Gunakan format mata uang Rupiah (IDR) saat menyebutkan harga.
4. Jawablah dengan singkat, padat, dan membantu.
5. Jika pengguna bingung, tanyakan warna favorit atau gaya yang biasa mereka pakai.
6. Selalu merespons dalam Bahasa Indonesia kecuali diminta lain oleh pengguna.
`;

export const getStylistResponse = async (userMessage: string, history: { role: 'user' | 'model', text: string }[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        maxOutputTokens: 500,
      }
    });

    return response.text || "Maaf, saya sedang mengalami kendala teknis. Ada yang bisa saya bantu lagi?";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Maaf, sepertinya saya sedang istirahat sejenak. Silakan tanya lagi nanti ya!";
  }
};

