export interface Message {
  role: 'user' | 'model';
  text: string;
}

export interface Review {
  id: string;
  userName: string;
  rating: number;
  comment: string;
  date: string;
  productName: string;
  helpfulCount: number;
}

import React, { useState } from 'react';
import { REVIEWS } from '../constants';
import ReviewsModal from './ReviewsModal';

const CustomerReviews: React.FC = () => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [votedReviews, setVotedReviews] = useState<Set<string>>(new Set());
  const [localReviews, setLocalReviews] = useState(REVIEWS);

  const toggleHelpful = (id: string) => {
    const newVoted = new Set(votedReviews);
    const isVoted = newVoted.has(id);

    if (isVoted) {
      newVoted.delete(id);
    } else {
      newVoted.add(id);
    }

    setLocalReviews(prev => prev.map(r => {
      if (r.id === id) {
        return { ...r, helpfulCount: isVoted ? r.helpfulCount - 1 : r.helpfulCount + 1 };
      }
      return r;
    }));
    setVotedReviews(newVoted);
  };

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <i 
        key={i} 
        className={`fa-solid fa-star text-xs ${i < rating ? 'text-orange-600' : 'text-stone-200'}`}
      />
    ));
  };

  return (
    <section className="py-24 bg-white border-t border-stone-100">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="text-center mb-16">
          <div className="inline-flex items-center space-x-2 bg-stone-100 px-4 py-2 rounded-full mb-6">
            <div className="flex -space-x-1">
              {[1, 2, 3].map(i => (
                <div key={i} className="w-6 h-6 rounded-full border-2 border-white bg-stone-300 overflow-hidden">
                  <img src={`https://i.pravatar.cc/100?img=${i + 10}`} alt="user" />
                </div>
              ))}
            </div>
            <span className="text-sm font-bold text-stone-900">4.9/5.0 Dari 200+ Pembeli</span>
          </div>
          <h2 className="text-4xl font-bold font-heading text-stone-900 tracking-tight">Apa Kata Mereka?</h2>
          <p className="mt-4 text-stone-500 max-w-2xl mx-auto">Kepuasan pelanggan adalah standar kualitas kami. Lihat ulasan jujur dari komunitas JTRIFT.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
          {localReviews.slice(0, 4).map((review) => (
            <div 
              key={review.id} 
              className="bg-stone-50 p-8 rounded-2xl border border-stone-100 hover:shadow-xl hover:-translate-y-1 transition-all duration-300 flex flex-col group/card"
            >
              <div className="flex justify-between items-start mb-4">
                <div className="flex">
                  {renderStars(review.rating)}
                </div>
              </div>

              <p className="text-stone-700 text-sm italic mb-6 leading-relaxed flex-grow">
                "{review.comment}"
              </p>

              <div className="mt-auto border-t border-stone-200 pt-4">
                <div className="flex justify-between items-end">
                  <div>
                    <p className="font-bold text-stone-900 text-sm">{review.userName}</p>
                    <p className="text-stone-400 text-[10px] uppercase tracking-widest mt-1">
                      {review.date}
                    </p>
                  </div>

                  <button 
                    onClick={() => toggleHelpful(review.id)}
                    className={`flex items-center space-x-1.5 px-2.5 py-1.5 rounded-lg text-[10px] font-bold transition-all ${
                      votedReviews.has(review.id)
                        ? 'bg-orange-600 text-white'
                        : 'bg-white text-stone-400 hover:text-stone-900 border border-stone-200'
                    }`}
                  >
                    <i className="fa-solid fa-thumbs-up"></i>
                    <span>{review.helpfulCount > 0 ? review.helpfulCount : ''} Bermanfaat</span>
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>

        <div className="mt-16 text-center">
          <button 
            onClick={() => setIsModalOpen(true)}
            className="text-stone-900 font-bold border-b-2 border-orange-600 pb-1 hover:text-orange-600 transition-colors uppercase tracking-widest text-xs outline-none"
          >
            Lihat Semua Ulasan <i className="fa-solid fa-arrow-right ml-2"></i>
          </button>
        </div>
      </div>

      <ReviewsModal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        reviews={localReviews} 
        onToggleHelpful={toggleHelpful}
        votedReviews={votedReviews}
      />
    </section>
  );
};

export default CustomerReviews;

import React from 'react';
import { Review } from '../types';

interface ReviewsModalProps {
  isOpen: boolean;
  onClose: () => void;
  reviews: Review[];
  onToggleHelpful: (id: string) => void;
  votedReviews: Set<string>;
}

const ReviewsModal: React.FC<ReviewsModalProps> = ({ isOpen, onClose, reviews, onToggleHelpful, votedReviews }) => {
  if (!isOpen) return null;

  const renderStars = (rating: number) => {
    return Array.from({ length: 5 }).map((_, i) => (
      <i 
        key={i} 
        className={`fa-solid fa-star text-xs ${i < rating ? 'text-orange-600' : 'text-stone-200'}`}
      />
    ));
  };

  return (
    <div className="fixed inset-0 z-[150] flex items-center justify-center p-4">
      {/* Overlay */}
      <div 
        className="absolute inset-0 bg-stone-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose} 
      />

      {/* Modal Content */}
      <div className="relative bg-white w-full max-w-2xl rounded-3xl shadow-2xl flex flex-col max-h-[85vh] overflow-hidden animate-in fade-in zoom-in duration-300">
        {/* Header */}
        <div className="p-6 border-b border-stone-100 flex justify-between items-center bg-white sticky top-0 z-10">
          <div>
            <h2 className="text-2xl font-bold font-heading text-stone-900">Ulasan Pelanggan</h2>
            <div className="flex items-center space-x-2 mt-1">
              <div className="flex text-orange-600">
                {renderStars(5)}
              </div>
              <span className="text-sm font-bold text-stone-500">4.9/5.0 (200+ ulasan)</span>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="w-10 h-10 flex items-center justify-center rounded-full hover:bg-stone-100 transition-colors text-stone-400 hover:text-stone-900"
          >
            <i className="fa-solid fa-xmark text-xl"></i>
          </button>
        </div>

        {/* Reviews List */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
          {reviews.map((review) => (
            <div key={review.id} className="border-b border-stone-100 pb-6 last:border-0 last:pb-0">
              <div className="flex justify-between items-start mb-2">
                <div>
                  <h4 className="font-bold text-stone-900">{review.userName}</h4>
                  <div className="flex items-center space-x-2 mt-1">
                    <div className="flex">{renderStars(review.rating)}</div>
                    <span className="text-[10px] text-stone-400 uppercase tracking-widest">{review.date}</span>
                  </div>
                </div>
                <div className="bg-stone-100 px-3 py-1 rounded-full">
                  <span className="text-[10px] font-bold text-stone-500 uppercase tracking-tight">Terverifikasi</span>
                </div>
              </div>
              <p className="text-stone-600 text-sm leading-relaxed mb-4">
                "{review.comment}"
              </p>

              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2 text-[10px] text-stone-400 bg-stone-50 p-2 rounded-lg inline-flex">
                  <i className="fa-solid fa-bag-shopping"></i>
                  <span className="font-medium">Membeli: {review.productName}</span>
                </div>

                <button 
                  onClick={() => onToggleHelpful(review.id)}
                  className={`flex items-center space-x-2 px-3 py-1.5 rounded-full text-xs font-bold transition-all ${
                    votedReviews.has(review.id)
                      ? 'bg-orange-600 text-white'
                      : 'bg-stone-100 text-stone-500 hover:bg-stone-200'
                  }`}
                >
                  <i className="fa-solid fa-thumbs-up text-[10px]"></i>
                  <span>{review.helpfulCount > 0 ? review.helpfulCount : ''} Membantu</span>
                </button>
              </div>
            </div>
          ))}
        </div>

        {/* Footer */}
        <div className="p-6 border-t border-stone-100 bg-stone-50 text-center">
          <p className="text-xs text-stone-400 italic">Terima kasih telah berkontribusi memberikan ulasan!</p>
        </div>
      </div>
    </div>
  );
};

export default ReviewsModal;

import React, { useState, useEffect, useRef } from 'react';
import Navbar from './components/Navbar';
import ProductCard from './components/ProductCard';
import CartSidebar from './components/CartSidebar';
import AIStylist from './components/AIStylist';
import CustomerReviews from './components/CustomerReviews';
import { PRODUCTS } from './constants';
import { Product, CartItem, Category } from './types';

const App: React.FC = () => {
  const [cartItems, setCartItems] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategory, setActiveCategory] = useState<Category>('All');
  const [searchQuery, setSearchQuery] = useState('');

  const heroRef = useRef<HTMLDivElement>(null);
  const collectionRef = useRef<HTMLDivElement>(null);
  const aboutRef = useRef<HTMLDivElement>(null);
  const contactRef = useRef<HTMLDivElement>(null);

  const filteredProducts = PRODUCTS.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                          p.category.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const addToCart = (product: Product, size: string) => {
    setCartItems(prev => {
      const existing = prev.find(item => item.id === product.id && item.selectedSize === size);
      if (existing) {
        return prev.map(item => 
          item.id === product.id && item.selectedSize === size 
            ? { ...item, quantity: item.quantity + 1 } 
            : item
        );
      }
      return [...prev, { ...product, selectedSize: size, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string, size: string) => {
    setCartItems(prev => prev.filter(item => !(item.id === id && item.selectedSize === size)));
  };

  const updateQuantity = (id: string, size: string, delta: number) => {
    setCartItems(prev => prev.map(item => {
      if (item.id === id && item.selectedSize === size) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const scrollToSection = (section: string) => {
    const refs: Record<string, React.RefObject<HTMLDivElement>> = {
      hero: heroRef,
      collection: collectionRef,
      about: aboutRef,
      contact: contactRef,
    };
    refs[section]?.current?.scrollIntoView({ behavior: 'smooth' });
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        cartCount={cartItems.reduce((s, i) => s + i.quantity, 0)} 
        onOpenCart={() => setIsCartOpen(true)}
        onNavigate={scrollToSection}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      <main className="flex-grow">
        {/* Hero Section */}
        <section ref={heroRef} className="relative h-[85vh] flex items-center overflow-hidden bg-stone-900">
          <div className="absolute inset-0 opacity-60">
            <img 
              src="https://images.unsplash.com/photo-1555689502-c4b22d76c56f?auto=format&fit=crop&q=80&w=1920" 
              className="w-full h-full object-cover" 
              alt="Model Streetwear" 
            />
          </div>
          <div className="absolute inset-0 bg-gradient-to-r from-stone-950 via-stone-900/40 to-transparent"></div>

          <div className="relative z-10 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-white">
            <h1 className="text-6xl md:text-8xl font-black font-heading tracking-tighter leading-none mb-6">
              DEFINISI KARYA<br />
              <span className="text-orange-600 italic">ANAK BANGSA.</span>
            </h1>
            <p className="max-w-xl text-lg md:text-xl text-stone-300 mb-10 font-light leading-relaxed">
              Jaket lokal premium yang memadukan estetika vintage dengan siluet street modern. Dibuat di Indonesia, dirancang untuk dunia.
            </p>
            <div className="flex flex-col sm:flex-row space-y-4 sm:space-y-0 sm:space-x-6">
              <button 
                onClick={() => scrollToSection('collection')}
                className="px-8 py-4 bg-orange-600 text-white font-bold rounded-lg hover:bg-orange-700 transition-all hover:scale-105 active:scale-95"
              >
                Lihat Koleksi Terbaru
              </button>
              <button 
                onClick={() => scrollToSection('about')}
                className="px-8 py-4 border border-white/30 backdrop-blur-sm text-white font-bold rounded-lg hover:bg-white hover:text-stone-900 transition-all"
              >
                Cerita Kami
              </button>
            </div>
          </div>
        </section>

        {/* Categories / Collection */}
        <section ref={collectionRef} className="py-24 bg-white">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between mb-12 space-y-4 md:space-y-0">
              <div>
                <h2 className="text-4xl font-bold font-heading text-stone-900 tracking-tight">
                  {searchQuery ? `Hasil untuk "${searchQuery}"` : 'Koleksi Saat Ini'}
                </h2>
                <p className="mt-2 text-stone-500">
                  {searchQuery ? `${filteredProducts.length} produk ditemukan` : 'Batch terbatas, detail maksimal di setiap jahitan.'}
                </p>
              </div>

              <div className="flex flex-wrap gap-2">
                {([['All', 'Semua'], ['Varsity', 'Varsity'], ['Bomber', 'Bomber'], ['Windbreaker', 'Windbreaker'], ['Vintage', 'Vintage'], ['Denim', 'Denim']] as [Category, string][]).map(([cat, label]) => (
                  <button
                    key={cat}
                    onClick={() => {
                      setActiveCategory(cat);
                      // Jika user cari lewat filter, scroll ke collection jika tidak terlihat
                      collectionRef.current?.scrollIntoView({ behavior: 'smooth' });
                    }}
                    className={`px-6 py-2 rounded-full text-sm font-bold transition-all ${
                      activeCategory === cat 
                        ? 'bg-stone-900 text-white' 
                        : 'bg-stone-100 text-stone-500 hover:bg-stone-200'
                    }`}
                  >
                    {label}
                  </button>
                ))}
              </div>
            </div>

            {filteredProducts.length > 0 ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-10">
                {filteredProducts.map(product => (
                  <ProductCard 
                    key={product.id} 
                    product={product} 
                    onAddToCart={addToCart} 
                  />
                ))}
              </div>
            ) : (
              <div className="py-20 text-center">
                <div className="inline-flex items-center justify-center w-20 h-20 bg-stone-100 rounded-full mb-6">
                  <i className="fa-solid fa-magnifying-glass text-3xl text-stone-300"></i>
                </div>
                <h3 className="text-2xl font-bold text-stone-900 mb-2">Pencarian Tidak Ditemukan</h3>
                <p className="text-stone-500 mb-8">Maaf, kami tidak menemukan jaket dengan kata kunci "{searchQuery}".</p>
                <button 
                  onClick={() => {
                    setSearchQuery('');
                    setActiveCategory('All');
                  }}
                  className="px-8 py-3 bg-stone-900 text-white font-bold rounded-lg hover:bg-black transition-all"
                >
                  Lihat Semua Produk
                </button>
              </div>
            )}
          </div>
        </section>

        {/* Featured Banner */}
        <section className="py-16 bg-stone-100 overflow-hidden">
          <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row items-center space-y-12 md:space-y-0 md:space-x-12">
            <div className="md:w-1/2 relative group">
              <img 
                src="https://images.unsplash.com/photo-1548126032-079a0fb0099d?auto=format&fit=crop&q=80&w=800" 
                className="rounded-3xl shadow-2xl transition-transform group-hover:scale-[1.02] duration-500" 
                alt="Proses Produksi" 
              />
              <div className="absolute -bottom-6 -right-6 w-32 h-32 bg-orange-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-12">
                <div className="text-center">
                  <span className="block text-4xl font-bold">100%</span>
                  <span className="text-[10px] font-bold uppercase tracking-widest">Buatan Lokal</span>
                </div>
              </div>
            </div>
            <div className="md:w-1/2">
              <h2 className="text-4xl font-bold font-heading text-stone-900 leading-tight mb-6">Kualitas adalah satu-satunya obsesi kami.</h2>
              <p className="text-stone-600 text-lg mb-8">
                Setiap bagian JTRIFT melalui proses kurasi yang ketat. Kami hanya menggunakan kain berat premium, ritsleting YKK, dan teknik bordir eksklusif untuk memastikan jaket Anda bertahan selama beberapa dekade, bukan sekadar musiman.
              </p>
              <ul className="space-y-4">
                {[
                  'Detail denim hand-distressed',
                  'Bahan berat 320gsm premium',
                  'Produksi terbatas (Maks 50 per gaya)',
                  'Jahitan yang diperkuat untuk ketahanan'
                ].map((item, idx) => (
                  <li key={idx} className="flex items-center space-x-3 text-stone-700">
                    <i className="fa-solid fa-check text-orange-600"></i>
                    <span className="font-medium">{item}</span>
                  </li>
                ))}
              </ul>
            </div>
          </div>
        </section>

        {/* Reviews Section */}
        <CustomerReviews />

        {/* Footer Contact */}
        <section ref={contactRef} className="bg-stone-950 text-white py-20">
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 grid grid-cols-1 md:grid-cols-4 gap-12">
            <div className="col-span-1 md:col-span-2">
              <span className="text-4xl font-black font-heading tracking-tighter mb-6 block">JTRIFT</span>
              <p className="text-stone-400 max-w-sm mb-8">
                Est. 2021. Lahir di Bekasi, menetapkan standar baru untuk street heritage Indonesia. Mengkurasi getaran, menjahit cerita.
              </p>
              <div className="flex space-x-6">
                <a href="#" className="text-2xl hover:text-orange-600 transition-colors"><i className="fa-brands fa-instagram"></i></a>
                <a href="#" className="text-2xl hover:text-orange-600 transition-colors"><i className="fa-brands fa-tiktok"></i></a>
                <a href="#" className="text-2xl hover:text-orange-600 transition-colors"><i className="fa-brands fa-whatsapp"></i></a>
              </div>
            </div>

            <div>
              <h4 className="font-bold uppercase tracking-widest text-sm mb-6 text-stone-500">Tautan Cepat</h4>
              <ul className="space-y-4 text-stone-300">
                <li><button onClick={() => scrollToSection('collection')} className="hover:text-white transition-colors">Belanja Semua</button></li>
                <li><button className="hover:text-white transition-colors">Lacak Pesanan</button></li>
                <li><button className="hover:text-white transition-colors">Panduan Ukuran</button></li>
                <li><button className="hover:text-white transition-colors">Syarat & Ketentuan</button></li>
              </ul>
            </div>

            <div>
              <h4 ref={aboutRef} className="font-bold uppercase tracking-widest text-sm mb-6 text-stone-500">Buletin</h4>
              <p className="text-stone-400 text-sm mb-4">Dapatkan akses awal untuk drop produk & diskon.</p>
              <div className="flex">
                <input 
                  type="email" 
                  placeholder="email@kamu.com" 
                  className="bg-stone-900 border-stone-800 rounded-l-lg px-4 py-2 flex-1 focus:ring-0 outline-none" 
                />
                <button className="bg-orange-600 px-4 py-2 rounded-r-lg font-bold hover:bg-orange-700 transition-colors">Gabung</button>
              </div>
            </div>
          </div>

          <div className="max-w-7xl mx-auto px-4 mt-20 pt-8 border-t border-stone-900 text-center text-stone-500 text-sm">
            &copy; {new Date().getFullYear()} JTRIFT Street Heritage. Hak cipta dilindungi undang-undang.
          </div>
        </section>
      </main>

      <CartSidebar 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)}
        items={cartItems}
        onRemove={removeFromCart}
        onUpdateQuantity={updateQuantity}
      />

      <AIStylist />
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';

interface NavbarProps {
  cartCount: number;
  onOpenCart: () => void;
  onNavigate: (section: string) => void;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, onOpenCart, onNavigate, searchQuery, setSearchQuery }) => {
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  const toggleSearch = () => {
    if (isSearchOpen && searchQuery === '') {
      setIsSearchOpen(false);
    } else {
      setIsSearchOpen(true);
    }
  };

  return (
    <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">
          <div className="flex items-center cursor-pointer" onClick={() => onNavigate('hero')}>
            <span className="text-3xl font-bold font-heading tracking-tighter text-stone-900">JTRIFT</span>
            <div className="ml-2 w-2 h-2 bg-orange-600 rounded-full"></div>
          </div>

          <div className="hidden md:flex space-x-8">
            <button onClick={() => onNavigate('collection')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Koleksi</button>
            <button onClick={() => onNavigate('about')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Tentang Kami</button>
            <button onClick={() => onNavigate('contact')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Kontak</button>
          </div>

          <div className="flex items-center space-x-5">
            <div className="flex items-center bg-stone-100 rounded-full transition-all duration-300 px-3 py-1.5 group">
              <input 
                ref={searchInputRef}
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Cari jaket..."
                className={`bg-transparent outline-none text-sm transition-all duration-300 ${isSearchOpen ? 'w-32 md:w-48 ml-2' : 'w-0 overflow-hidden'}`}
                onBlur={() => { if (searchQuery === '') setIsSearchOpen(false); }}
              />
              <button 
                onClick={toggleSearch}
                className={`p-1 text-stone-600 hover:text-stone-900 transition-colors ${isSearchOpen && 'text-orange-600'}`}
              >
                <i className={`fa-solid ${isSearchOpen && searchQuery !== '' ? 'fa-xmark' : 'fa-magnifying-glass'} text-lg`}></i>
              </button>
            </div>

            <button 
              onClick={onOpenCart}
              className="relative p-2 text-stone-600 hover:text-stone-900 transition-colors"
            >
              <i className="fa-solid fa-bag-shopping text-2xl"></i>
              {cartCount > 0 && (
                <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-white transform translate-x-1/2 -translate-y-1/2 bg-orange-600 rounded-full">
                  {cartCount}
                </span>
              )}
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

