interface CartSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (id: string, size: string) => void;
  onUpdateQuantity: (id: string, size: string, delta: number) => void;
}

const CartSidebar: React.FC<CartSidebarProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity }) => {
  const [isConfirming, setIsConfirming] = useState(false);
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  if (!isOpen) return null;

  const handleClose = () => {
    setIsConfirming(false);
    onClose();
  };

  const handleProcessCheckout = () => {
    alert('Terima kasih! Pesanan Anda sedang diproses. Tim JTRIFT akan segera menghubungi Anda.');
    setIsConfirming(false);
    onClose();
    // Logic for actual checkout would go here
  };

  return (
    <div className="fixed inset-0 z-[100] overflow-hidden">
      <div className="absolute inset-0 bg-black/50 transition-opacity" onClick={handleClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md bg-white shadow-xl flex flex-col relative">
