            ) : (
              <div className="py-20 text-center">
                <div className="inline-flex items-center justify-center w-20 h-20 bg-stone-100 rounded-full mb-6">
                  <i className="fa-solid fa-magnifying-glass text-3xl text-stone-300"></i>
                </div>
                <h3 className="text-2xl font-bold text-stone-900 mb-2">Pencarian Tidak Ditemukan</h3>
                <p className="text-stone-500 mb-8">Maaf, kami tidak menemukan jaket dengan kata kunci "{searchQuery}".</p>
                <button 
                  onClick={() => {
                    setSearchQuery('');
                    setActiveCategory('All');
                  }}
                  className="px-8 py-3 bg-stone-900 text-white font-bold rounded-lg hover:bg-black transition-all"
                >
                  Lihat Semua Produk
                </button>
              </div>
            )}
          </div>
        </section>

        {/* Featured Banner */}
        <section className="py-16 bg-stone-100 overflow-hidden">
