import React, { useState } from 'react';
import { CartItem } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface CartSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (id: string, size: string) => void;
  onUpdateQuantity: (id: string, size: string, delta: number) => void;
  onCheckoutSuccess?: (items: CartItem[], total: number) => void;
}

const CartSidebar: React.FC<CartSidebarProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity, onCheckoutSuccess }) => {
  const [isConfirming, setIsConfirming] = useState(false);
  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  if (!isOpen) return null;

  const handleClose = () => {
    setIsConfirming(false);
    onClose();
  };

  const handleProcessCheckout = () => {
    if (onCheckoutSuccess) {
      onCheckoutSuccess(items, total);
    }
    setIsConfirming(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[100] overflow-hidden">
      <div className="absolute inset-0 bg-black/50 transition-opacity" onClick={handleClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md bg-white shadow-xl flex flex-col relative">
          <div className="p-6 border-b border-stone-200 flex justify-between items-center">
            <h2 className="text-xl font-bold font-heading">Keranjang Kamu</h2>
            <button onClick={handleClose} className="text-stone-500 hover:text-stone-900">
              <i className="fa-solid fa-xmark text-2xl"></i>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-400">
                <i className="fa-solid fa-bag-shopping text-6xl mb-4 opacity-20"></i>
                <p>Keranjang kamu masih kosong.</p>
                <button 
                  onClick={handleClose}
                  className="mt-4 text-orange-600 font-semibold hover:underline"
                >
                  Mulai Belanja
                </button>
              </div>
            ) : (
              <ul className="space-y-6">
                {items.map((item) => (
                  <li key={`${item.id}-${item.selectedSize}`} className="flex space-x-4">
                    <img src={item.image} alt={item.name} className="w-20 h-24 object-cover rounded" />
                    <div className="flex-1">
                      <h3 className="font-semibold text-stone-900">{item.name}</h3>
                      <p className="text-sm text-stone-500">Ukuran: {item.selectedSize}</p>
                      <div className="flex items-center justify-between mt-2">
                        <div className="flex items-center border border-stone-200 rounded">
                          <button 
                            onClick={() => onUpdateQuantity(item.id, item.selectedSize, -1)}
                            className="px-2 py-1 hover:bg-stone-100"
                          >
                            <i className="fa-solid fa-minus text-xs"></i>
                          </button>
                          <span className="px-3 py-1 text-sm font-medium">{item.quantity}</span>
                          <button 
                            onClick={() => onUpdateQuantity(item.id, item.selectedSize, 1)}
                            className="px-2 py-1 hover:bg-stone-100"
                          >
                            <i className="fa-solid fa-plus text-xs"></i>
                          </button>
                        </div>
                        <span className="font-medium">{FORMAT_CURRENCY(item.price * item.quantity)}</span>
                      </div>
                    </div>
                    <button 
                      onClick={() => onRemove(item.id, item.selectedSize)}
                      className="text-stone-400 hover:text-red-500 transition-colors"
                    >
                      <i className="fa-solid fa-trash-can"></i>
                    </button>
                  </li>
                ))}
              </ul>
            )}
          </div>

          <div className="p-6 border-t border-stone-200 bg-stone-50">
            {isConfirming ? (
              <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                <div className="bg-orange-50 border border-orange-100 rounded-xl p-4 mb-4">
                  <p className="text-stone-800 text-sm font-medium mb-1">Konfirmasi Pesanan?</p>
                  <p className="text-stone-500 text-xs leading-relaxed">
