                  </p>
                </div>
                <div className="flex space-x-3">
                  <button 
                    onClick={() => setIsConfirming(false)}
                    className="flex-1 py-4 border border-stone-300 text-stone-600 font-bold rounded-lg hover:bg-white transition-colors"
                  >
                    Kembali
                  </button>
                  <button 
                    onClick={handleProcessCheckout}
                    className="flex-1 py-4 bg-orange-600 text-white font-bold rounded-lg hover:bg-orange-700 shadow-lg shadow-orange-600/20 transition-all active:scale-95"
                  >
                    Ya, Proses
                  </button>
                </div>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-6">
                  <span className="text-stone-600">Subtotal</span>
                  <span className="text-xl font-bold">{FORMAT_CURRENCY(total)}</span>
                </div>
                <button 
                  onClick={() => setIsConfirming(true)}
                  disabled={items.length === 0}
                  className="w-full py-4 bg-stone-900 text-white font-bold rounded-lg hover:bg-black transition-colors disabled:bg-stone-300 disabled:cursor-not-allowed flex items-center justify-center space-x-2"
                >
                  <span>Checkout Sekarang</span>
                  <i className="fa-solid fa-arrow-right text-xs opacity-50"></i>
                </button>
                <p className="mt-4 text-center text-xs text-stone-500 uppercase tracking-widest">
                  Gratis ongkir seluruh Indonesia untuk pesanan di atas 500rb
                </p>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

