interface ProductCardProps {
  product: Product;
  onAddToCart: (product: Product, size: string) => void;
  onToggleWishlist: (product: Product) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart, onToggleWishlist, isWishlisted }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [isHovered, setIsHovered] = useState(false);

  return (
    <div 
      className="group relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className="aspect-[3/4] overflow-hidden rounded-2xl bg-stone-200 relative">
        <img 
          src={product.image} 
          alt={product.name} 
          className="h-full w-full object-cover object-center transition-transform duration-700 group-hover:scale-110"
        />

        {/* Top Indicators */}
        <div className="absolute top-4 left-4 flex flex-col space-y-2">
          {product.isNew && (
            <span className="bg-orange-600 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg">
              Baru
            </span>
          )}
          {product.stock < 5 && (
            <span className="bg-stone-900 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg">
              Stok Tipis
            </span>
          )}
        </div>

        {/* Wishlist Button */}
        <button 
          onClick={(e) => {
            e.stopPropagation();
            onToggleWishlist(product);
          }}
          className={`absolute top-4 right-4 w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg ${
            isWishlisted 
              ? 'bg-orange-600 text-white' 
              : 'bg-white/80 backdrop-blur-md text-stone-400 hover:text-orange-600'
          }`}
        >
          <i className={`${isWishlisted ? 'fa-solid' : 'fa-regular'} fa-heart text-lg`}></i>
        </button>

        {/* Quick Add Overlay */}
        <div className={`absolute inset-0 bg-black/20 backdrop-blur-sm transition-opacity duration-300 flex flex-col justify-end p-6 ${isHovered ? 'opacity-100' : 'opacity-0'}`}>
          <div className="bg-white rounded-xl p-4 shadow-2xl transform translate-y-0 transition-transform duration-500">
            <p className="text-xs font-bold uppercase text-stone-400 mb-2">Pilih Ukuran</p>
            <div className="flex flex-wrap gap-2 mb-4">
              {product.sizes.map((size) => (
                <button
                  key={size}
                  onClick={() => setSelectedSize(size)}
                  className={`w-10 h-10 rounded-md border flex items-center justify-center text-sm font-bold transition-all ${
                    selectedSize === size 
                      ? 'bg-stone-900 text-white border-stone-900 shadow-inner' 
                      : 'border-stone-200 text-stone-600 hover:border-stone-900'
                  }`}
                >
                  {size}
                </button>
              ))}
            </div>
            <button
              onClick={() => {
                if (selectedSize) {
                  onAddToCart(product, selectedSize);
                  setSelectedSize('');
                } else {
                  alert('Silakan pilih ukuran terlebih dahulu');
                }
              }}
              className="w-full bg-orange-600 text-white py-3 rounded-lg font-bold hover:bg-orange-700 transition-colors flex items-center justify-center space-x-2 shadow-lg active:scale-95"
            >
              <i className="fa-solid fa-plus text-xs"></i>
              <span>Tambah ke Keranjang</span>
            </button>
          </div>
        </div>
      </div>

      <div className="mt-4 flex justify-between items-start px-1">
        <div>
          <h3 className="text-lg font-bold text-stone-900 font-heading group-hover:text-orange-600 transition-colors">{product.name}</h3>
          <p className="mt-1 text-sm text-stone-500 uppercase tracking-widest text-[10px] font-bold">{product.category}</p>
        </div>
        <div className="text-right">
          <p className="text-lg font-bold text-stone-900">{FORMAT_CURRENCY(product.price)}</p>
          <p className="text-[10px] text-stone-400 font-medium">Cicilan 0%</p>
        </div>
      </div>
    </div>
  );
};

