      <WishlistSidebar 
        isOpen={isWishlistOpen} 
        onClose={() => setIsWishlistOpen(false)} 
        items={wishlistItems} 
        productStocks={productStocks}
        onRemove={toggleWishlist} 
        onMoveToCart={handleMoveToCart}
