import React, { useState } from 'react';
import { Product } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface ProductCardProps {
  product: Product;
  currentStock: number;
  onAddToCart: (product: Product, size: string) => void;
  onToggleWishlist: (product: Product) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, currentStock, onAddToCart, onToggleWishlist, isWishlisted }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [isHovered, setIsHovered] = useState(false);

  const isOutOfStock = currentStock <= 0;

  return (
    <div 
      id={`product-${product.id}`}
      className="group relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`aspect-[3/4] overflow-hidden rounded-2xl bg-stone-200 relative ${isOutOfStock ? 'grayscale' : ''}`}>
        {/* Primary Image */}
        <img 
          src={product.image} 
          alt={product.name} 
          className={`h-full w-full object-cover object-center transition-all duration-700 ease-in-out transform ${
            isHovered && product.secondaryImage ? 'opacity-0 scale-105' : 'opacity-100 scale-100'
          } group-hover:scale-110`}
        />

        {/* Secondary Image (Cross-fade) */}
        {product.secondaryImage && (
          <img 
            src={product.secondaryImage} 
            alt={`${product.name} detail`} 
            className={`absolute inset-0 h-full w-full object-cover object-center transition-all duration-700 ease-in-out transform ${
              isHovered ? 'opacity-100 scale-110' : 'opacity-0 scale-100'
            }`}
          />
        )}

        {/* Top Indicators */}
        <div className="absolute top-4 left-4 flex flex-col space-y-2 z-10">
          {product.isNew && !isOutOfStock && (
            <span className="bg-orange-600 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg">
              Baru
            </span>
          )}
          {currentStock > 0 && currentStock < 10 && (
            <span className="bg-stone-900 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg animate-pulse">
              Stok Tipis
            </span>
          )}
          {isOutOfStock && (
            <span className="bg-red-600 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg">
              Habis Terjual
            </span>
          )}
        </div>

        {/* Wishlist Heart Button (Quick Access) */}
        <button 
          onClick={(e) => {
            e.stopPropagation();
            onToggleWishlist(product);
          }}
          className={`absolute top-4 right-4 w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg z-20 hover:scale-110 active:scale-90 ${
            isWishlisted 
              ? 'bg-orange-600 text-white' 
              : 'bg-white/80 backdrop-blur-md text-stone-400 hover:text-orange-600'
          }`}
        >
          <i className={`${isWishlisted ? 'fa-solid' : 'fa-regular'} fa-heart text-lg`}></i>
        </button>

        {/* Quick Add Overlay */}
        {!isOutOfStock && (
          <div className={`absolute inset-0 bg-black/20 backdrop-blur-sm transition-opacity duration-300 flex flex-col justify-end p-6 z-20 ${isHovered ? 'opacity-100' : 'opacity-0'}`}>
            <div className={`bg-white rounded-xl p-4 shadow-2xl transform transition-transform duration-500 ${isHovered ? 'translate-y-0' : 'translate-y-10'}`}>
              <div className="flex justify-between items-center mb-2">
                <p className="text-xs font-bold uppercase text-stone-400">Pilih Ukuran</p>
                <div className="flex items-center space-x-1.5">
                  <div className={`w-1.5 h-1.5 rounded-full ${currentStock < 5 ? 'bg-red-500 animate-pulse' : 'bg-green-500'}`}></div>
                  <span className={`text-[10px] font-bold ${currentStock < 5 ? 'text-red-500' : 'text-stone-500'}`}>
                    Tersisa {currentStock} pcs
                  </span>
                </div>
              </div>
              <div className="flex flex-wrap gap-2 mb-4">
                {product.sizes.map((size) => (
                  <button
                    key={size}
                    onClick={() => setSelectedSize(size)}
                    className={`w-10 h-10 rounded-md border flex items-center justify-center text-sm font-bold transition-all ${
                      selectedSize === size 
                        ? 'bg-stone-900 text-white border-stone-900 shadow-inner' 
                        : 'border-stone-200 text-stone-600 hover:border-stone-900'
                    }`}
                  >
                    {size}
                  </button>
                ))}
              </div>
              <div className="flex flex-col space-y-2">
                <button
                  onClick={() => {
                    if (selectedSize) {
                      onAddToCart(product, selectedSize);
                      setSelectedSize('');
                    } else {
                      alert('Silakan pilih ukuran terlebih dahulu');
                    }
                  }}
                  className="w-full bg-orange-600 text-white py-3 rounded-lg font-bold hover:bg-orange-700 transition-colors flex items-center justify-center space-x-2 shadow-lg active:scale-95"
                >
                  <i className="fa-solid fa-bag-shopping text-xs"></i>
                  <span>Beli Sekarang</span>
                </button>
                <button
                  onClick={() => onToggleWishlist(product)}
                  className={`w-full py-2 rounded-lg text-[10px] font-bold uppercase tracking-widest flex items-center justify-center space-x-2 border transition-all ${
                    isWishlisted 
                    ? 'border-orange-200 bg-orange-50 text-orange-600' 
                    : 'border-stone-200 text-stone-500 hover:bg-stone-50'
                  }`}
                >
                  <i className={`${isWishlisted ? 'fa-solid' : 'fa-regular'} fa-heart`}></i>
                  <span>{isWishlisted ? 'Hapus Wishlist' : 'Tambah Wishlist'}</span>
                </button>
              </div>
            </div>
          </div>
        )}

        {isOutOfStock && (
          <div className="absolute inset-0 bg-black/40 backdrop-blur-[2px] flex items-center justify-center p-6 z-20">
            <div className="bg-white/10 border border-white/20 backdrop-blur-md px-6 py-3 rounded-full">
              <span className="text-white font-bold uppercase tracking-widest text-xs">Sold Out</span>
            </div>
          </div>
        )}
      </div>

      <div className="mt-4 flex justify-between items-start px-1">
        <div>
          <h3 className={`text-lg font-bold font-heading transition-colors ${isOutOfStock ? 'text-stone-400' : 'text-stone-900 group-hover:text-orange-600'}`}>{product.name}</h3>
          <p className="mt-1 text-sm text-stone-500 uppercase tracking-widest text-[10px] font-bold">{product.category}</p>
        </div>
        <div className="text-right">
          <p className={`text-lg font-bold ${isOutOfStock ? 'text-stone-400' : 'text-stone-900'}`}>{FORMAT_CURRENCY(product.price)}</p>
          <p className="text-[10px] text-stone-400 font-medium">Cicilan 0%</p>
        </div>
      </div>
    </div>
  );
};

