import React, { useEffect, useState } from 'react';

interface SplashScreenProps {
  onComplete: () => void;
}

const SplashScreen: React.FC<SplashScreenProps> = ({ onComplete }) => {
  const [isVisible, setIsVisible] = useState(true);
  const [showTagline, setShowTagline] = useState(false);

  useEffect(() => {
    // Show tagline after a short delay
    const taglineTimer = setTimeout(() => setShowTagline(true), 600);

    // Start exit animation
    const exitTimer = setTimeout(() => setIsVisible(false), 2400);

    // Cleanup and complete
    const completeTimer = setTimeout(() => onComplete(), 3000);

    return () => {
      clearTimeout(taglineTimer);
      clearTimeout(exitTimer);
      clearTimeout(completeTimer);
    };
  }, [onComplete]);

  return (
    <div className={`fixed inset-0 z-[1000] flex flex-col items-center justify-center bg-stone-950 transition-all duration-700 ease-in-out ${isVisible ? 'opacity-100' : 'opacity-0 -translate-y-full'}`}>
      <div className="relative">
        {/* Animated Brand Name */}
        <h1 className="text-6xl md:text-8xl font-black font-heading text-white tracking-tighter animate-in fade-in slide-in-from-bottom-10 duration-1000">
          JTRIFT<span className="text-orange-600">.</span>
        </h1>

        {/* Animated Subtitle */}
        <div className={`mt-4 overflow-hidden transition-all duration-1000 ${showTagline ? 'max-h-20 opacity-100' : 'max-h-0 opacity-0'}`}>
          <p className="text-stone-500 uppercase tracking-[0.4em] text-[10px] md:text-xs font-bold text-center">
            STREET HERITAGE • EST. 2021
          </p>
        </div>

        {/* Minimalist Progress Bar */}
        <div className="absolute -bottom-8 left-0 w-full h-[1px] bg-stone-800 overflow-hidden">
          <div className="h-full bg-orange-600 animate-progress origin-left"></div>
        </div>
      </div>

      <div className="absolute bottom-10 text-stone-700 text-[10px] uppercase tracking-widest font-bold">
        Premium Local Movement
      </div>

      <style>{`
        @keyframes progress {
          0% { transform: scaleX(0); }
          100% { transform: scaleX(1); }
        }
        .animate-progress {
          animation: progress 2.5s cubic-bezier(0.65, 0, 0.35, 1) forwards;
        }
      `}</style>
    </div>
  );
};

