import React, { useState } from 'react';
import { Product } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface ProductCardProps {
  product: Product;
  currentStock: number;
  onAddToCart: (product: Product, size: string) => void;
  onToggleWishlist: (product: Product) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, currentStock, onAddToCart, onToggleWishlist, isWishlisted }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [isHovered, setIsHovered] = useState(false);
  const [isPulsing, setIsPulsing] = useState(false);

  const isOutOfStock = currentStock <= 0;

  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsPulsing(true);
    onToggleWishlist(product);
    setTimeout(() => setIsPulsing(false), 400);
  };

  return (
    <div 
      id={`product-${product.id}`}
      className="group relative animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-both"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`aspect-[3/4] overflow-hidden rounded-2xl bg-stone-100 relative ${isOutOfStock ? 'grayscale' : ''} shadow-sm group-hover:shadow-xl transition-shadow duration-300`}>
        {/* Product Image - Always static primary image */}
        <img 
          src={product.image} 
          alt={product.name} 
