import React, { useState } from 'react';
import { Product } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface WishlistSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: Product[];
  productStocks: Record<string, number>;
  onRemove: (product: Product) => void;
  onMoveToCart: (product: Product) => void;
}

const WishlistSidebar: React.FC<WishlistSidebarProps> = ({ isOpen, onClose, items, productStocks, onRemove, onMoveToCart }) => {
  const [removingId, setRemovingId] = useState<string | null>(null);

  if (!isOpen) return null;

  const handleRemoveWithAnimation = (product: Product) => {
    setRemovingId(product.id);
    // Wait for animation to finish before calling parent remove
    setTimeout(() => {
      onRemove(product);
      setRemovingId(null);
    }, 400);
  };

  return (
    <div className="fixed inset-0 z-[120] overflow-hidden">
      <div className="absolute inset-0 bg-black/50 transition-opacity backdrop-blur-sm" onClick={onClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md bg-white shadow-2xl flex flex-col relative animate-in slide-in-from-right duration-300">
          {/* Header */}
          <div className="p-6 border-b border-stone-100 flex justify-between items-center bg-white sticky top-0 z-10 shadow-sm">
            <div className="flex items-center space-x-3">
              <div className="w-10 h-10 rounded-full bg-orange-600 flex items-center justify-center text-white shadow-lg shadow-orange-600/20">
                <i className="fa-solid fa-heart"></i>
              </div>
              <div>
                <h2 className="text-xl font-bold font-heading text-stone-900">Wishlist</h2>
                <p className="text-[10px] text-stone-400 uppercase tracking-[0.2em] font-bold">Favorit Kamu</p>
              </div>
            </div>
            <button onClick={onClose} className="w-10 h-10 flex items-center justify-center rounded-full text-stone-400 hover:text-stone-900 hover:bg-stone-100 transition-all">
              <i className="fa-solid fa-xmark text-2xl"></i>
            </button>
          </div>

          {/* Body */}
          <div className="flex-1 overflow-y-auto p-6 custom-scrollbar bg-stone-50/50">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-400 space-y-6">
                <div className="relative">
                  <div className="w-24 h-24 bg-white rounded-full flex items-center justify-center shadow-inner">
                    <i className="fa-regular fa-heart text-5xl opacity-10"></i>
                  </div>
                  <div className="absolute -bottom-2 -right-2 w-10 h-10 bg-orange-100 rounded-full flex items-center justify-center border-4 border-white">
                    <i className="fa-solid fa-magnifying-glass text-orange-600 text-xs"></i>
                  </div>
                </div>
                <div className="text-center">
                  <p className="font-bold text-stone-900 text-lg">Wishlist Kamu Kosong</p>
                  <p className="text-xs mt-2 max-w-[240px] leading-relaxed text-stone-500">
                    Sepertinya kamu belum menemukan jaket yang cocok. Yuk cek koleksi terbaru kami!
                  </p>
                </div>
                <button 
                  onClick={onClose} 
                  className="px-10 py-4 bg-stone-900 text-white text-xs font-bold rounded-xl uppercase tracking-[0.2em] hover:bg-black transition-all shadow-xl active:scale-95"
                >
                  Mulai Belanja
                </button>
              </div>
            ) : (
              <ul className="space-y-4">
                {items.map((item) => {
                  const currentStock = productStocks[item.id] || 0;
                  const isOutOfStock = currentStock <= 0;
                  const isRemoving = removingId === item.id;

                  return (
                    <li 
                      key={item.id} 
                      className={`bg-white p-4 rounded-2xl shadow-sm border border-stone-100 flex space-x-4 transition-all hover:shadow-md animate-in fade-in slide-in-from-right-4 duration-300 
                        ${isOutOfStock ? 'opacity-60' : ''} 
                        ${isRemoving ? 'animate-exit-wishlist' : ''}`}
                    >
                      <div className="relative group shrink-0">
                        <img src={item.image} alt={item.name} className={`w-24 h-32 object-cover rounded-xl shadow-sm transition-all ${isOutOfStock ? 'grayscale' : 'group-hover:scale-105'}`} />
                        <button 
                          onClick={() => handleRemoveWithAnimation(item)}
                          className="absolute -top-2 -left-2 w-8 h-8 bg-white shadow-md border border-stone-100 rounded-full flex items-center justify-center text-stone-400 hover:text-red-500 hover:scale-110 transition-all z-10"
                          title="Hapus dari favorit"
                        >
                          <i className="fa-solid fa-xmark text-xs"></i>
                        </button>
                        {isOutOfStock && (
                          <div className="absolute inset-0 bg-black/40 rounded-xl flex items-center justify-center">
                             <span className="bg-red-600 text-white text-[8px] font-bold px-2 py-1 rounded-full uppercase tracking-tighter shadow-lg">Sold Out</span>
                          </div>
                        )}
                      </div>
                      <div className="flex-1 flex flex-col py-1">
                        <div className="flex justify-between items-start">
                          <div>
                            <h3 className={`font-bold text-sm leading-tight transition-colors ${isOutOfStock ? 'text-stone-400' : 'text-stone-900'}`}>{item.name}</h3>
                            <p className="text-[10px] text-stone-400 mt-1 uppercase tracking-widest font-black">{item.category}</p>
                          </div>
                        </div>

                        <div className="mt-2 flex items-center justify-between">
                          <span className={`font-bold text-sm ${isOutOfStock ? 'text-stone-400' : 'text-stone-900'}`}>{FORMAT_CURRENCY(item.price)}</span>
                          {currentStock < 10 && currentStock > 0 && (
                            <span className="text-[9px] font-bold text-orange-600 bg-orange-50 px-2 py-0.5 rounded-md border border-orange-100 animate-pulse">Sisa {currentStock}</span>
                          )}
                        </div>

                        <div className="mt-auto">
                          <button 
                            onClick={() => onMoveToCart(item)}
                            disabled={isOutOfStock}
                            className={`w-full py-2.5 text-[10px] font-bold uppercase tracking-[0.1em] rounded-lg transition-all flex items-center justify-center space-x-2 border ${
                              isOutOfStock 
                                ? 'bg-stone-50 text-stone-300 border-stone-100 cursor-not-allowed' 
                                : 'bg-stone-900 text-white border-stone-900 hover:bg-black shadow-lg shadow-stone-200 active:scale-95'
                            }`}
                          >
                            <i className={`fa-solid ${isOutOfStock ? 'fa-hourglass-end' : 'fa-cart-plus'} text-[10px]`}></i>
                            <span>{isOutOfStock ? 'Stok Habis' : 'Pilih Ukuran'}</span>
                          </button>
                        </div>
                      </div>
                    </li>
                  );
                })}
              </ul>
            )}
          </div>

          {/* Footer */}
          {items.length > 0 && (
            <div className="p-6 border-t border-stone-100 bg-white shadow-[0_-4px_20px_rgba(0,0,0,0.03)]">
              <div className="flex items-center justify-between mb-6">
                <span className="text-xs text-stone-500 font-medium">Total Favorit</span>
                <span className="text-base font-bold text-stone-900">{items.length} Jaket</span>
              </div>
              <button 
                onClick={onClose}
                className="w-full py-4 border border-stone-200 text-stone-600 font-bold rounded-xl hover:bg-stone-50 hover:text-stone-900 transition-all text-xs uppercase tracking-[0.2em]"
              >
                Lanjut Belanja
              </button>
              <p className="mt-4 text-center text-[10px] text-stone-400 font-medium leading-relaxed italic">
                Simpan koleksi favoritmu di sini. Stok setiap batch sangat terbatas!
              </p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default WishlistSidebar;

import React, { useState, useRef, useEffect } from 'react';

interface NavbarProps {
  cartCount: number;
  wishlistCount: number;
  onOpenCart: () => void;
  onOpenWishlist: () => void;
  onNavigate: (section: string) => void;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, wishlistCount, onOpenCart, onOpenWishlist, onNavigate, searchQuery, setSearchQuery }) => {
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [isCartAnimate, setIsCartAnimate] = useState(false);
  const searchInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (isSearchOpen && searchInputRef.current) {
      searchInputRef.current.focus();
    }
  }, [isSearchOpen]);

  // Trigger cart animation when count changes
  useEffect(() => {
    if (cartCount > 0) {
      setIsCartAnimate(true);
      const timer = setTimeout(() => setIsCartAnimate(false), 400);
      return () => clearTimeout(timer);
    }
  }, [cartCount]);

  const toggleSearch = () => {
    if (isSearchOpen && searchQuery === '') {
      setIsSearchOpen(false);
    } else {
      setIsSearchOpen(true);
    }
  };

  return (
    <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-stone-200">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center h-20">
          <div className="flex items-center cursor-pointer" onClick={() => onNavigate('hero')}>
            <span className="text-3xl font-bold font-heading tracking-tighter text-stone-900">JTRIFT</span>
            <div className="ml-2 w-2 h-2 bg-orange-600 rounded-full"></div>
          </div>

          <div className="hidden md:flex space-x-8">
            <button onClick={() => onNavigate('collection')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Koleksi</button>
            <button onClick={() => onNavigate('about')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Tentang Kami</button>
            <button onClick={() => onNavigate('contact')} className="text-stone-600 hover:text-stone-900 font-medium transition-colors">Kontak</button>
          </div>

          <div className="flex items-center space-x-3">
            <div className="flex items-center bg-stone-100 rounded-full transition-all duration-300 px-3 py-1.5 group">
              <input 
                ref={searchInputRef}
                type="text" 
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Cari jaket..."
                className={`bg-transparent outline-none text-sm transition-all duration-300 ${isSearchOpen ? 'w-32 md:w-48 ml-2' : 'w-0 overflow-hidden'}`}
                onBlur={() => { if (searchQuery === '') setIsSearchOpen(false); }}
              />
              <button 
                onClick={toggleSearch}
                className={`p-1 text-stone-600 hover:text-stone-900 transition-colors ${isSearchOpen && 'text-orange-600'}`}
              >
                <i className={`fa-solid ${isSearchOpen && searchQuery !== '' ? 'fa-xmark' : 'fa-magnifying-glass'} text-lg`}></i>
              </button>
            </div>

            <button 
              onClick={onOpenWishlist}
              className="relative p-2 text-stone-600 hover:text-orange-600 transition-colors"
              aria-label="Wishlist"
            >
              <i className="fa-regular fa-heart text-2xl"></i>
              {wishlistCount > 0 && (
                <span className="absolute top-0 right-0 inline-flex items-center justify-center px-1.5 py-0.5 text-[10px] font-bold leading-none text-white transform translate-x-1/2 -translate-y-1/2 bg-stone-900 rounded-full">
                  {wishlistCount}
                </span>
              )}
            </button>

            <button 
              onClick={onOpenCart}
              className={`relative p-2 text-stone-600 hover:text-stone-900 transition-colors ${isCartAnimate ? 'animate-cart-pop' : ''}`}
              aria-label="Cart"
            >
              <i className="fa-solid fa-bag-shopping text-2xl"></i>
              {cartCount > 0 && (
                <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-white transform translate-x-1/2 -translate-y-1/2 bg-orange-600 rounded-full">
                  {cartCount}
                </span>
              )}
            </button>
          </div>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState } from 'react';
import { Product } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface ProductCardProps {
  product: Product;
  currentStock: number;
  onAddToCart: (product: Product, size: string) => void;
  onToggleWishlist: (product: Product) => void;
  isWishlisted: boolean;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, currentStock, onAddToCart, onToggleWishlist, isWishlisted }) => {
  const [selectedSize, setSelectedSize] = useState<string>('');
  const [isHovered, setIsHovered] = useState(false);
  const [isPulsing, setIsPulsing] = useState(false);
  const [isAdding, setIsAdding] = useState(false);
  const [isAddedSuccess, setIsAddedSuccess] = useState(false);

  const isOutOfStock = currentStock <= 0;

  const handleFavoriteClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    setIsPulsing(true);
    onToggleWishlist(product);
    setTimeout(() => setIsPulsing(false), 400);
  };

  const handleAddToCart = () => {
    if (!selectedSize) {
      alert('Pilih ukuran dulu ya, Bro!');
      return;
    }

    setIsAdding(true);

    // Artificial delay to show loading state
    setTimeout(() => {
      onAddToCart(product, selectedSize);
      setIsAdding(false);
      setIsAddedSuccess(true);
      setSelectedSize('');

      // Reset success state after 2 seconds
      setTimeout(() => setIsAddedSuccess(false), 2000);
    }, 600);
  };

  return (
    <div 
      id={`product-${product.id}`}
      className="group relative animate-in fade-in slide-in-from-bottom-4 duration-700 fill-mode-both"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`aspect-[3/4] overflow-hidden rounded-2xl bg-stone-100 relative ${isOutOfStock ? 'grayscale' : ''} shadow-sm group-hover:shadow-xl transition-shadow duration-300`}>
        {/* Product Image - Always static primary image */}
        <img 
          src={product.image} 
          alt={product.name} 
          className="h-full w-full object-cover object-center"
        />

        {/* Badge Overlay */}
        <div className="absolute top-4 left-4 flex flex-col gap-2 z-10 pointer-events-none">
          {product.isNew && !isOutOfStock && (
            <span className="bg-orange-600 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg">
              Batch Baru
            </span>
          )}
          {currentStock > 0 && currentStock < 5 && (
            <span className="bg-stone-900 text-white px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-widest shadow-lg animate-pulse">
              Limit Terakhir
            </span>
          )}
        </div>

        {/* Favorite Trigger with Pulse Animation */}
        <button 
          onClick={handleFavoriteClick}
          className={`absolute top-4 right-4 w-10 h-10 rounded-full flex items-center justify-center transition-all duration-300 shadow-lg z-20 hover:scale-110 active:scale-90 ${
            isWishlisted 
              ? 'bg-orange-600 text-white' 
              : 'bg-white/90 backdrop-blur-md text-stone-400 hover:text-orange-600'
          } ${isPulsing ? 'animate-heartbeat' : ''}`}
        >
          <i className={`${isWishlisted ? 'fa-solid' : 'fa-regular'} fa-heart text-lg`}></i>
        </button>

        {/* Action Overlay */}
        {!isOutOfStock && (
          <div className={`absolute inset-0 bg-stone-900/10 backdrop-blur-[2px] transition-all duration-300 flex flex-col justify-end p-5 z-20 ${isHovered || isAdding || isAddedSuccess ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
            <div className={`bg-white rounded-2xl p-5 shadow-2xl transform transition-all duration-300 ${isHovered || isAdding || isAddedSuccess ? 'translate-y-0 opacity-100' : 'translate-y-4 opacity-0'}`}>
              {!isAddedSuccess ? (
                <>
                  <div className="flex justify-between items-center mb-3">
                    <p className="text-[10px] font-bold uppercase tracking-widest text-stone-400">Pilih Size</p>
                    <span className="text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded">Ready Stock</span>
                  </div>
                  <div className="flex flex-wrap gap-2 mb-4">
                    {product.sizes.map((size) => (
                      <button
                        key={size}
                        onClick={() => setSelectedSize(size)}
                        className={`w-9 h-9 rounded-lg border-2 flex items-center justify-center text-xs font-bold transition-all ${
                          selectedSize === size 
                            ? 'bg-stone-900 text-white border-stone-900' 
                            : 'border-stone-100 text-stone-600 hover:border-stone-400'
                        }`}
                      >
                        {size}
                      </button>
                    ))}
                  </div>
                  <button
                    onClick={handleAddToCart}
                    disabled={isAdding}
                    className="w-full bg-orange-600 text-white py-3.5 rounded-xl font-bold hover:bg-orange-700 transition-all flex items-center justify-center space-x-2 shadow-xl shadow-orange-600/20 active:scale-[0.97]"
                  >
                    {isAdding ? (
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                    ) : (
                      <>
                        <i className="fa-solid fa-cart-plus text-xs"></i>
                        <span className="text-sm">Tambahkan</span>
                      </>
                    )}
                  </button>
                </>
              ) : (
                <div className="py-6 flex flex-col items-center justify-center space-y-3 animate-bounce-in">
                  <div className="w-12 h-12 bg-green-100 text-green-600 rounded-full flex items-center justify-center">
                    <i className="fa-solid fa-check text-xl"></i>
                  </div>
                  <p className="text-sm font-bold text-stone-900 uppercase tracking-widest">Berhasil Masuk!</p>
                </div>
              )}
            </div>
          </div>
        )}

        {isOutOfStock && (
          <div className="absolute inset-0 bg-stone-900/60 backdrop-blur-sm flex items-center justify-center p-6 z-20">
            <div className="bg-white/20 border border-white/30 backdrop-blur-md px-5 py-2.5 rounded-full">
              <span className="text-white font-bold uppercase tracking-[0.2em] text-[10px]">Habis Terjual</span>
            </div>
          </div>
        )}
      </div>

      {/* Product Details */}
      <div className="mt-5 flex justify-between items-start px-1">
        <div>
          <h3 className={`text-base font-bold font-heading transition-colors duration-300 ${isOutOfStock ? 'text-stone-400' : 'text-stone-900 group-hover:text-orange-600'}`}>
            {product.name}
          </h3>
          <p className="mt-1 text-[10px] text-stone-400 uppercase tracking-[0.15em] font-black">
            {product.category} Series
          </p>
        </div>
        <div className="text-right">
          <p className={`text-base font-bold ${isOutOfStock ? 'text-stone-400' : 'text-stone-900'}`}>
            {FORMAT_CURRENCY(product.price)}
          </p>
          <div className="flex items-center justify-end space-x-1 mt-1">
             <i className="fa-solid fa-star text-[8px] text-orange-500"></i>
             <span className="text-[10px] text-stone-400 font-bold">4.9</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductCard;

import React, { useState } from 'react';
import { CartItem, PaymentMethod } from '../types';
import { FORMAT_CURRENCY } from '../constants';

interface CartSidebarProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  productStocks: Record<string, number>;
  onRemove: (id: string, size: string) => void;
  onUpdateQuantity: (id: string, size: string, delta: number) => void;
  onCheckoutSuccess?: (items: CartItem[], total: number, payment: PaymentMethod) => void;
}

type CheckoutStep = 'cart' | 'payment' | 'confirm';

const CartSidebar: React.FC<CartSidebarProps> = ({ isOpen, onClose, items, productStocks, onRemove, onUpdateQuantity, onCheckoutSuccess }) => {
  const [step, setStep] = useState<CheckoutStep>('cart');
  const [selectedPayment, setSelectedPayment] = useState<PaymentMethod | null>(null);
  const [removingItemId, setRemovingItemId] = useState<string | null>(null);

  const total = items.reduce((sum, item) => sum + (item.price * item.quantity), 0);

  if (!isOpen) return null;

  const handleClose = () => {
    setStep('cart');
    setSelectedPayment(null);
    onClose();
  };

  const handleRemoveWithAnimation = (id: string, size: string) => {
    setRemovingItemId(`${id}-${size}`);
    setTimeout(() => {
      onRemove(id, size);
      setRemovingItemId(null);
    }, 400);
  };

  const handleProcessCheckout = () => {
    if (onCheckoutSuccess && selectedPayment) {
      onCheckoutSuccess(items, total, selectedPayment);
    }
    setStep('cart');
    setSelectedPayment(null);
    onClose();
  };

  const paymentOptions: { id: PaymentMethod; label: string; icon: string; desc: string }[] = [
    { id: 'QRIS', label: 'QRIS (Gopay/OVO/Dana)', icon: 'fa-qrcode', desc: 'Scan instan, proses otomatis.' },
    { id: 'Bank Transfer', label: 'Virtual Account', icon: 'fa-building-columns', desc: 'BCA, Mandiri, BNI, BRI.' },
    { id: 'E-Wallet', label: 'E-Wallet Direct', icon: 'fa-wallet', desc: 'Pembayaran langsung via GoPay/ShopeePay.' },
  ];

  return (
    <div className="fixed inset-0 z-[100] overflow-hidden">
      <div className="absolute inset-0 bg-black/50 transition-opacity" onClick={handleClose} />

      <div className="absolute inset-y-0 right-0 max-w-full flex">
        <div className="w-screen max-w-md bg-white shadow-xl flex flex-col relative">
          <div className="p-6 border-b border-stone-200 flex justify-between items-center">
            <div className="flex items-center space-x-3">
              <h2 className="text-xl font-bold font-heading">
                {step === 'cart' ? 'Keranjang Kamu' : step === 'payment' ? 'Pilih Pembayaran' : 'Konfirmasi Akhir'}
              </h2>
              <div className="flex space-x-1">
                {[1, 2, 3].map(i => (
                  <div key={i} className={`w-1.5 h-1.5 rounded-full ${
                    (step === 'cart' && i === 1) || 
                    (step === 'payment' && i <= 2) || 
                    (step === 'confirm' && i <= 3) 
                      ? 'bg-orange-600' : 'bg-stone-200'
                  }`} />
                ))}
              </div>
            </div>
            <button onClick={handleClose} className="text-stone-500 hover:text-stone-900">
              <i className="fa-solid fa-xmark text-2xl"></i>
            </button>
          </div>

          <div className="flex-1 overflow-y-auto p-6 custom-scrollbar">
            {items.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-stone-400">
                <i className="fa-solid fa-bag-shopping text-6xl mb-4 opacity-20"></i>
                <p>Keranjang kamu masih kosong.</p>
                <button onClick={handleClose} className="mt-4 text-orange-600 font-semibold hover:underline">
                  Mulai Belanja
                </button>
              </div>
            ) : (
              <>
                {step === 'cart' && (
                  <ul className="space-y-6 animate-in fade-in duration-300">
                    {items.map((item) => {
                      const availableStock = productStocks[item.id] || 0;
                      const isRemoving = removingItemId === `${item.id}-${item.selectedSize}`;
                      return (
                        <li 
                          key={`${item.id}-${item.selectedSize}`} 
                          className={`flex space-x-4 transition-all ${isRemoving ? 'animate-exit-cart' : ''}`}
                        >
                          <img src={item.image} alt={item.name} className="w-20 h-24 object-cover rounded shadow-sm" />
                          <div className="flex-1">
                            <div className="flex justify-between items-start">
                              <h3 className="font-semibold text-stone-900 text-sm leading-tight">{item.name}</h3>
                              <button 
                                onClick={() => handleRemoveWithAnimation(item.id, item.selectedSize)} 
                                className="text-stone-300 hover:text-red-500 transition-colors ml-2"
                              >
                                <i className="fa-solid fa-trash-can text-xs"></i>
                              </button>
                            </div>
                            <p className="text-[10px] text-stone-500 uppercase tracking-widest font-bold mt-1">Ukuran: {item.selectedSize}</p>

                            <div className="flex items-center justify-between mt-3">
                              <div className="flex items-center border border-stone-200 rounded-lg overflow-hidden bg-stone-50">
                                <button 
                                  onClick={() => onUpdateQuantity(item.id, item.selectedSize, -1)} 
                                  className="px-2.5 py-1 hover:bg-stone-100 text-stone-500"
                                >
                                  <i className="fa-solid fa-minus text-[10px]"></i>
                                </button>
                                <span className="px-3 py-1 text-xs font-bold w-8 text-center">{item.quantity}</span>
                                <button 
                                  onClick={() => onUpdateQuantity(item.id, item.selectedSize, 1)} 
                                  disabled={availableStock <= 0}
                                  className={`px-2.5 py-1 text-stone-500 ${availableStock <= 0 ? 'opacity-30 cursor-not-allowed' : 'hover:bg-stone-100'}`}
                                >
                                  <i className="fa-solid fa-plus text-[10px]"></i>
                                </button>
                              </div>
                              <span className="font-bold text-sm">{FORMAT_CURRENCY(item.price * item.quantity)}</span>
                            </div>
                            {availableStock < 5 && availableStock > 0 && (
                               <p className="text-[10px] text-orange-600 font-bold mt-2 flex items-center">
                                 <i className="fa-solid fa-circle-exclamation mr-1"></i>
                                 Sisa {availableStock} pcs di stok
                               </p>
                            )}
                            {availableStock <= 0 && (
                               <p className="text-[10px] text-red-600 font-bold mt-2">Stok terakhir sudah di tanganmu!</p>
                            )}
                          </div>
                        </li>
                      );
                    })}
                  </ul>
                )}

                {step === 'payment' && (
                  <div className="space-y-4 animate-in slide-in-from-right-4 duration-300">
                    <p className="text-xs font-bold text-stone-400 uppercase tracking-widest mb-4">Metode Tersedia</p>
                    {paymentOptions.map((opt) => (
                      <button
                        key={opt.id}
                        onClick={() => setSelectedPayment(opt.id)}
                        className={`w-full text-left p-4 rounded-2xl border-2 transition-all flex items-center space-x-4 ${
                          selectedPayment === opt.id 
                            ? 'border-orange-600 bg-orange-50/30' 
                            : 'border-stone-100 hover:border-stone-200 bg-stone-50'
                        }`}
                      >
                        <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-xl shadow-sm ${
                          selectedPayment === opt.id ? 'bg-orange-600 text-white' : 'bg-white text-stone-400'
                        }`}>
                          <i className={`fa-solid ${opt.icon}`}></i>
                        </div>
                        <div>
                          <p className="font-bold text-sm text-stone-900">{opt.label}</p>
                          <p className="text-[10px] text-stone-500 mt-0.5">{opt.desc}</p>
                        </div>
                        {selectedPayment === opt.id && (
                          <div className="ml-auto text-orange-600">
                            <i className="fa-solid fa-circle-check"></i>
                          </div>
                        )}
                      </button>
                    ))}
                  </div>
                )}

                {step === 'confirm' && (
                  <div className="animate-in slide-in-from-right-4 duration-300">
                    <div className="bg-stone-900 text-white rounded-2xl p-6 mb-6">
                      <h4 className="text-xs font-bold text-orange-400 uppercase tracking-widest mb-4">Detail Pesanan</h4>
                      <div className="space-y-3 mb-6">
                        {items.map((item, idx) => (
                          <div key={idx} className="flex justify-between text-xs">
                            <span className="text-stone-400">{item.quantity}x {item.name} ({item.selectedSize})</span>
                            <span className="font-bold">{FORMAT_CURRENCY(item.price * item.quantity)}</span>
                          </div>
                        ))}
                      </div>
                      <div className="border-t border-white/10 pt-4 flex justify-between items-center">
                        <span className="text-sm">Metode Bayar</span>
                        <span className="text-sm font-bold bg-orange-600/20 px-3 py-1 rounded-full text-orange-400">{selectedPayment}</span>
                      </div>
                    </div>
                    <div className="p-4 border-2 border-dashed border-stone-200 rounded-2xl">
                      <p className="text-xs text-stone-500 leading-relaxed text-center">
                        Pesananmu diproses secara real-time. Stok dikunci selama sesi pembayaran ini.
                      </p>
                    </div>
                  </div>
                )}
              </>
            )}
          </div>

          <div className="p-6 border-t border-stone-200 bg-stone-50">
            <div className="flex justify-between items-center mb-6">
              <span className="text-stone-600 font-medium">Total Tagihan</span>
              <span className="text-xl font-bold text-stone-900">{FORMAT_CURRENCY(total)}</span>
            </div>

            {step === 'cart' && (
              <button 
                onClick={() => setStep('payment')}
                disabled={items.length === 0}
                className="w-full py-4 bg-stone-900 text-white font-bold rounded-xl hover:bg-black transition-all disabled:bg-stone-200 disabled:cursor-not-allowed flex items-center justify-center space-x-2 shadow-lg shadow-stone-200"
              >
                <span>Checkout Sekarang</span>
                <i className="fa-solid fa-arrow-right text-xs opacity-50"></i>
              </button>
            )}

            {step === 'payment' && (
              <div className="flex space-x-3">
                <button 
                  onClick={() => setStep('cart')}
                  className="flex-1 py-4 border border-stone-300 text-stone-600 font-bold rounded-xl hover:bg-white transition-colors"
