import { GoogleGenAI, Type } from "@google/genai";
import { PRODUCTS } from "../constants";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

const SYSTEM_INSTRUCTION = `
Anda adalah AI Personal Stylist dari JTRIFT. JTRIFT adalah brand jaket lokal Indonesia yang berfokus pada streetwear, varsity, dan vintage.
Bantu pelanggan menemukan jaket yang sesuai.

Katalog Produk (Gunakan ID ini untuk rekomendasi):
${JSON.stringify(PRODUCTS.map(p => ({ id: p.id, name: p.name, price: p.price, category: p.category, description: p.description })))}

Tugas Anda:
1. Analisis keinginan pengguna (misal: "Jaket keren buat motoran", "Varsity yang vintage").
2. Berikan narasi gaya yang trendy (Gunakan 'Bro', 'Sis', 'Keren parah').
3. JIKA ada produk yang relevan di katalog, sertakan ID-nya dalam array 'recommendedProductIds'. Maksimal 3 produk.
4. Output HARUS dalam format JSON.

Format JSON Output:
{
  "text": "String narasi gaya Anda",
  "recommendedProductIds": ["ID1", "ID2"]
}
`;

export const getStylistResponse = async (userMessage: string, history: { role: 'user' | 'model', text: string }[]) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history.map(h => ({ role: h.role === 'user' ? 'user' : 'model', parts: [{ text: h.text }] })),
        { role: 'user', parts: [{ text: userMessage }] }
      ],
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        temperature: 0.7,
        maxOutputTokens: 800,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            text: { type: Type.STRING },
            recommendedProductIds: { 
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["text"]
        }
      }
    });

    try {
      const data = JSON.parse(response.text || '{}');
      return {
        text: data.text || "Ada lagi yang bisa saya bantu?",
        productIds: data.recommendedProductIds || []
      };
    } catch (e) {
      return { text: response.text || "Maaf, sistem sedang sibuk.", productIds: [] };
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    return { text: "Maaf, sepertinya saya sedang istirahat sejenak. Silakan tanya lagi nanti ya!", productIds: [] };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { getStylistResponse } from '../services/geminiService';
import { Message, Product } from '../types';
import { PRODUCTS, FORMAT_CURRENCY } from '../constants';

const AIStylist: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Halo! Saya Stylist Pribadi JTRIFT. Lagi cari jaket yang fresh hari ini? Kasih tahu saya apa yang kamu butuhkan!' }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMessage }]);
    setIsLoading(true);

    const result = await getStylistResponse(userMessage, messages.map(m => ({ role: m.role, text: m.text })));
    setMessages(prev => [...prev, { 
      role: 'model', 
      text: result.text, 
      productIds: result.productIds 
    }]);
    setIsLoading(false);
  };

  const scrollToProduct = (id: string) => {
    const element = document.getElementById(`product-${id}`);
    if (element) {
      setIsOpen(false);
      element.scrollIntoView({ behavior: 'smooth', block: 'center' });
      element.classList.add('ring-4', 'ring-orange-500/30', 'rounded-2xl', 'duration-1000');
      setTimeout(() => element.classList.remove('ring-4', 'ring-orange-500/30'), 3000);
    }
  };

  const CompactProductCard: React.FC<{ productId: string }> = ({ productId }) => {
    const product = PRODUCTS.find(p => p.id === productId);
    if (!product) return null;

    return (
      <div className="bg-white rounded-xl border border-stone-100 p-2 flex items-center space-x-3 hover:shadow-md transition-shadow group animate-in slide-in-from-left-2 duration-300">
