        .animate-scan {
          animation: scan 2s linear infinite;
        }

        @keyframes stitch-progress {
          0% { transform: scaleX(0); }
          100% { transform: scaleX(1); }
        }
        .animate-stitch-progress {
          animation: stitch-progress 2.5s cubic-bezier(0.65, 0, 0.35, 1) forwards;
        }

        @keyframes glitch {
          0% { transform: translate(0); }
          20% { transform: translate(-2px, 2px); }
          40% { transform: translate(-2px, -2px); }
          60% { transform: translate(2px, 2px); }
          80% { transform: translate(2px, -2px); }
          100% { transform: translate(0); }
        }
        .animate-glitch {
          animation: glitch 3s infinite linear alternate-reverse;
        }

        h1::before, h1::after {
          content: attr(data-text);
          position: absolute;
          top: 0;
          left: 0;
          width: 100%;
          height: 100%;
          opacity: 0.8;
        }
        h1::before {
          color: #ff3c00;
          z-index: -1;
          animation: glitch 0.4s cubic-bezier(.25,.46,.45,.94) both infinite;
          clip-path: polygon(0 0, 100% 0, 100% 33%, 0 33%);
          transform: translate(-2px, -2px);
        }
        h1::after {
          color: #00fff2;
          z-index: -2;
          animation: glitch 0.4s cubic-bezier(.25,.46,.45,.94) reverse both infinite;
          clip-path: polygon(0 67%, 100% 67%, 100% 100%, 0 100%);
          transform: translate(2px, 2px);
          opacity: 0.2;
        }
      `}</style>
    </div>
  );
};

